if (typeof createImageBitmap !== 'undefined' && typeof Blob !== 'undefined') {
  try {
    const blob = new Blob([minimalJxl], { type: 'image/jxl' });
    const bm = await createImageBitmap(blob);
    const ok = bm.width === 1 && bm.height === 1;
    bm.close();
    return ok;
  } catch {
    return false;
  }
