export function probeWebGpuAdapter(): Promise<boolean> {
  return (_gpuAdapterPromise ??= (async () => {
    try {
      const gpu = (navigator as any)?.gpu;
      if (!gpu) return false;
      return (await gpu.requestAdapter()) !== null;
    } catch { return false; }
  })());
}

if (isNode) {
